INSERT INTO `faq_cat_question` VALUES (28,24,'गाय भैसों में मुख्यतः कौन-कौन सी संक्रामक बीमारियां पाई जाती है ?','<p style=\"font-size:40px;\">गाय भैसों में मुख्यतः निम्न संक्रामक बीमारियां पाई जाती है।</p><p style=\"font-size:40px;\">1. गलघोंटू 2. लंगडा बुखार 3. खुरपका व मुंहपका रोग 4. निमोनिया</p>','2021-11-26 06:15:44','Y'),(29,24,'गलघोंटू बीमारी के लक्षण एवं बचाव के क्या उपाय हैं ?','<p style=\"font-size:40px;\">यह रोग मुख्य रूप से गाय एवं भैस में पाया जाता है, एवं मानसून के समय</p><p style=\"font-size:40px;\">व्यापक रूप से फैलता है। इस बीमारी में पशु को तेज बुखार आता है एवं पशु के कन्ठ और निचले जबड़े के बीच कष्ठदायक कठोर सूजन हो जाती है तथा श्वास लेने में काफी कठिनाई होती है। इस रोग से बचाव हेतु प्रतिवर्ष पशु को वर्षा ऋतु से पूर्व इस रोग का टीका लगवा लेना चाहिए।</p>','2021-11-26 06:16:05','Y'),(30,24,'गाय भैसों में मुख्यतः कौन-कौन सी संक्रामक बीमारियां पाई जाती है ? ','<p style=\"font-size:40px;\">&nbsp;गाय भैसों में मुख्यतः निम्न संक्रामक बीमारियां पाई जाती है।</p>','2021-11-26 06:16:26','Y'),(31,24,'लंगड़ा बुखार बीमारी के लक्षण एवं बचाव के क्या उपाय हैं ?','<p style=\"font-size:40px;\">&nbsp;यह रोग मुख्य रूप से गाय, भैंस एवं भेडों में होता है। इस रोग में तेज बुखार आता है एवं घुटने के ऊपर वाले हिस्से में सूजन होती है एवं जो शुरू में गर्म एवं कष्टदायक हो जाती है सूजन के ऊपर वाली चमडी सूख कर कडी हो जाती है एवं दबाने पर चड़चड़ाती है। यह चड़चड़ाहट सूजन में गैस भरी होने के कारण होती है। यह रोग की प्रमुख पहचान है। इस रोग से बचाव हेतु प्रतिवर्ष वर्षा ऋतु से पूर्व इस रोग का टीका लगवा लेना चाहिए एवं रोग की सम्भावना होने पर तुरन्त पशुचिकित्सक से परामर्श लेना चाहिए।</p>','2021-11-26 06:18:18','Y'),(32,24,'खुरपका व मुंहपका रोग क्या है ?','<p style=\"font-size:40px;\">विभाजित खुरों वाले पशुओं में तेजी से फैलने वाला वायरस जनित छूतदार रोग है</p><p style=\"font-size:40px;\">एवं इस बीमारी में दुधारू पशुओं का दूध कम या नहीं के बराबर हो जाता है। इस रोग के प्रमुख लक्षण तेज बुखार, मुँह से रस्सी की तरह लार गिरना एवं छाले बनना, थनों एवं खुरो के बीच छाले व सूजन पड़ना है। रोग होने पर छालो को लाल दवा से दिन में दो बार धोवें तथा पशु चिकित्सक की सलाह पर औषधि का प्रयोग व लेप करें। रोग के बचाव हेतु वर्ष में दो बार नियमित टीकाकरण करावें।</p>','2021-11-26 06:18:39','Y'),(33,24,'पी.पी.आर. रोग किसमे होता है एवं इसके प्रमुख लक्षण क्या है ?','<p style=\"font-size:40px;\">यह रोग भेड व बकरी में फैलने वाला वायरल रोग है। इस रोग में रोगी पशु को तेज बुखार आता है, मुँह, मसुड़े व जीभ पर छाले व होठों पर सूजन आ जाती है, खॉसी व निमोनिया हो जाता है तथा पशु को दस्त हो जाते है जिससे शरीर में पानी की कमी आ जाती है।</p>','2021-11-26 06:18:58','Y'),(34,24,'क्या पी.पी.आर रोग की रोकथाम की जा सकती है ?','<p style=\"font-size:40px;\">हाँ, चार माह से ऊपर की आयु वाली भेड़ व बकरीयों में टीका लगवाया जा सकता है जिससे पशु तीन वर्ष तक इस रोग से सुरक्षित रहता है।</p>','2021-11-26 06:19:15','Y'),(35,24,'पशु को पागल कुत्ते के काटने पर क्या करना चाहिए ?','<p style=\"font-size:40px;\">पागल कुत्ते के काटने के तुरन्त बाद कटे हुए घाव को साबुन से अच्छी तरह धोना चाहिए तथा उसी दिन से एन्टी रेबीज टीके 0,3,7,14,28 व 90 दिन पर लगवाना</p>','2021-11-26 06:19:34','Y'),(36,24,'विभाग द्वारा कौन-कौन सी बीमारियों के टीके उपलब्ध करवाये जाते हैं एवं किस समय ये टीके लगवाने चाहिए? ','<p style=\"font-size:40px;\">विभाग द्वारा निम्नानुसार टीके लगवाये जाते हैं -</p><p style=\"font-size:40px;\">गलघोंटू&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;वार्षिक&nbsp; &nbsp; &nbsp; &nbsp; अप्रेल-जुलाई</p><p style=\"font-size:40px;\">&nbsp;लगड़ा बुखार&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; वार्षिक&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; अप्रेल-जून</p><p style=\"font-size:40px;\">&nbsp;खुरपका मुंहपका&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;6 माह&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;सितम्बर-अक्टूबर</p><p style=\"font-size:40px;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;मार्च-अप्रेल</p><p style=\"font-size:40px;\">&nbsp;फड़किया&nbsp; &nbsp; वार्षिक&nbsp; &nbsp;अप्रेल-जून</p><p style=\"font-size:40px;\">&nbsp;भेडमाता वाषिक&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;नवम्बर-दिसम्बर</p>','2021-11-26 06:19:53','Y'),(37,24,'रोग प्रकोप होने पर बचाव के क्या उपाय है।','<p style=\"font-size:40px;\">1. रोग के प्रारम्भिक लक्षण देखते ही रोगी पशु को अन्य स्वस्थ पशुओं से अलग स्थान</p><p style=\"font-size:40px;\">पर रखें एवं दाना-चारा व पानी की व्यवस्था अलग बरतनों में करें। 2. रोगी पशु को रोगी पशु के उपचार हेतु पशु चिकित्सक से सम्पर्क करें।&nbsp;</p><p style=\"font-size:40px;\">3. पशु चिकित्सक की सलाह से आस-पास के स्वस्थ पशुओं में टीकाकरण करायें।</p><p style=\"font-size:40px;\">&nbsp;4. रोग ग्रस्त क्षेत्र में पशुओं का आवागमन/परिवहन नहीं करें। संक्रामक रोग से मृत</p><p style=\"font-size:40px;\">पशु को गांव के बाहर लगभग 1.5 मीटर गहरे गड्ढे में चूने या नमक के साथ दबा</p><p style=\"font-size:40px;\">देंवे।&nbsp;</p><p style=\"font-size:40px;\">5. मृत पशु के सम्पर्क में रही वस्तुओं व स्थान को भी फिनाइल, लाल दवा आदि से कीटाणु रहित करें।</p>','2021-11-26 06:20:23','Y'),(38,24,'पशुओं को कृमिनाशक औषधि कब पिलानी चाहिए ?','<p style=\"font-size:40px;\">पशुओं को वर्ष में दो बार कृमिनाशक औषधि पिलानी चाहिए।</p>','2021-11-26 06:21:04','Y'),(39,24,'चीचड़ी ज्वर अथवा रक्त मूत्र रोग कैसे होता है एवं इससे बचाव के क्या उपाय है?','<p style=\"font-size: 40px;\">इस रोग को फैलाने वाले परजीवी चीचड़ मे रहते हैं जो पशु के शरीर में प्रवेश पाकर बीमारी के लक्षण पैदा करते हैं। इस बीमारी में एकाएक तेज बुखार आता है एवं पेशाब का रंग गाढ़ा लाल हो जाता है तथा पशु को श्वास लेने में दिक्कत होती है। इस रोग की रोकथाम हेतु पशुशाला में नियमित रूप से कीटनाशक दवाईयों का इस्तेमाल कर मक्खी, जूं चीचड़ आदि से मुक्त रखना चाहिए।</p>','2021-11-26 06:21:19','Y');
/*!40000 ALTER TABLE `faq_cat_question` ENABLE KEYS */;
UNLOCK TABLES;

