DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `delivery_charges` float DEFAULT '0',
  `discount` float DEFAULT '0',
  `wallet` int DEFAULT NULL,
  `sub_total` float NOT NULL DEFAULT '0',
  `total_amount` float DEFAULT '0',
  `slot_id` int NOT NULL,
  `order_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `razorpay_order_id` varchar(250) DEFAULT NULL,
  `razorpay_payment_id` varchar(250) DEFAULT NULL,
  `razorpay_signature` varchar(250) DEFAULT NULL,
  `order_status` enum('Cancelled','Pending','Dispatch','Delivered') NOT NULL DEFAULT 'Pending',
  `payment_status` enum('approved','pending','rejected') NOT NULL DEFAULT 'pending',
  `address_type` varchar(250) DEFAULT NULL,
  `billng_address` text,
  `delivery_date` datetime DEFAULT NULL,
  `latitude` float DEFAULT NULL,
  `longitude` float DEFAULT NULL,
  `locality` varchar(200) DEFAULT NULL,
  `payment_mode` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=399 DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

