INSERT INTO `products` VALUES (44,'बिनोला (काकड़ा) खल ','गौरी ब्रांड','100 किलोग्राम','23061010',NULL,'गौरी ब्रांड बिनोला खल में लगभग 8.5 -9% ऑइल ह ओर 22-24 % प्रोटीन ह इसे यह करीब 10- 15 में पांच गुना पानी को अपने अंदर सोख लेती ह ','Y','2021-09-23 06:51:19'),(45,'बिनोला (काकड़ा) खल ','मंगलमोती ब्रांड ','100 किलोग्राम ','23061010',NULL,'मंगलमोती ब्रांड में ऑइल मात्रा 8-8.5 % ओर प्रोटीन मात्रा लगभग 22% है ','Y','2021-09-23 06:54:12'),(46,'बिनोला (काकड़ा) खल  ','राजा ब्रांड ','Qunital','23061010',NULL,'राजा ब्रांड बिनौला खल में करीब 8-8.5  परसेंट ऑइल और  21-22 परसेंट प्रोटीन होता है और लगभग 10-15 मिनिट में पूरा फूलकर भीग जाता है ','Y','2021-09-23 06:55:18'),(47,'मोटा काकड़ा','--','Qunital','12072900',NULL,'फैट और प्रोटीन से युक्त आपके पशुओं के लिए सबसे उचित,आयल कंटेंट 17-20% तक फैटमें बढ़ोतरी 18-19% नमी 10%','Y','2021-09-23 06:56:24'),(48,'चार्डी काकड़ा','--','Quintal','12072900',NULL,'फैट और प्रोटीन से युक्त आपके पशुओं के लिए सबसे उचित,आयल कंटेंट 15-16 % तक फैटमें बढ़ोतरी 15-17% नमी 10%','Y','2021-09-23 06:58:46'),(49,'रेगुलर पशु आहार  (पैलेट्स) ','गौरी नंदा ब्रांड ','Bags','23099010',NULL,'यह पशुआहार पेलेट्स के रूप में होता है इसमें करीब 18 परसेंट के लगभग प्रोटीन और करीब 3 परसेंट के लगभग फैट होता है जो कि पशुओं के लिए उचित आहार है','Y','2021-09-23 07:00:10'),(50,'मंगलम पशु आहार','गौरी नंदा ','Bags','23099010',NULL,'यह पशुआहार मेस पाऊडर के रूप में होता है इसमें करीब 19-20 % प्रोटीन व 3% फेट होता है यह पशुआहार अपने अंदर 5 गुना पानी सोखने की विशेषता है ','Y','2021-09-23 07:01:05'),(51,'गेंहू चापड़','B l','Bags','230210',NULL,'फैट 1-1.5%  प्रोटीन 13% ','Y','2021-09-23 07:01:58'),(52,'डलिंटर काकड़ा','गौरी ब्राण्ड','Qunital','12072900',NULL,'फैट और प्रोटीन से युक्त आपके पशुओं के लिए सबसे उचित,fiber  24%  % तक फैटमें बढ़ोतरी 17-19% नमी 11-12% crude protein - 20-21%','Y','2021-09-23 07:02:51'),(53,'मक्का दलिया','गौरी ब्रांड ','किलोग्राम ','230210',NULL,'फैट 7-8 प्रोटीन 13-14% ','Y','2021-09-23 07:03:42'),(54,'मूँग खंडा','--','Qunital','230210',NULL,'फैट 1-1.5%  प्रोटीन 13% ','Y','2021-09-23 07:04:25'),(55,'काकड़ा तेल','--','Kgs','15122100',NULL,'only oil (tin weight not included)','Y','2021-09-23 07:05:07'),(56,'सरसों खल','--','Qunital','23069021',NULL,'सरसों खल में ऑइल की मात्रा 7 %  प्रोटीन 37-38% जो पशुओं के लिए लाभदायक है ','Y','2021-09-23 07:06:19'),(57,'गेहूँ दलिया','गौरी ब्रांड','kg','230990',NULL,'गेहूँ दलिया गौरी ब्रांड','Y','2022-08-01 13:05:00'),(61,'मोटा काकड़ा दलिया','गौरी ब्रांड ','Kg','1207',NULL,'मोटा काकड़ा दलिया','Y','2022-08-17 13:35:51'),(68,'चना चूरी','गौरी ब्रांड ','kg','2306',NULL,'चना चूरी ','Y','2022-09-29 12:42:38');
