INSERT INTO `static` VALUES (26,'Terms And Condition','terms-and-conditions','<style>\r\np {font-size:40px !important; padding:20px; text-align:justify; margin-bottom:30px}\r\n</style>\r\n\r\n<p>राहत पधारने के लिए धन्यवाद। यह गोपनीयता नीति आपको बताती है कि हम इस साइट पर एकत्रित व्यक्तिगत जानकारी का उपयोग कैसे करते हैं। साइट का उपयोग करने या कोई व्यक्तिगत जानकारी जमा करने से पहले कृपया इस गोपनीयता नीति को पढ़ें। साइट का उपयोग करके, आप इस गोपनीयता नीति में वर्णित प्रथाओं को स्वीकार कर रहे हैं। इन प्रथाओं को बदला जा सकता है, लेकिन कोई भी परिवर्तन पोस्ट किया जाएगा और परिवर्तन केवल आगे की गतिविधियों और सूचनाओं पर लागू होंगे, पूर्वव्यापी आधार पर नहीं। जब भी आप साइट पर जाते हैं तो आपको गोपनीयता नीति की समीक्षा करने के लिए प्रोत्साहित किया जाता है ताकि यह सुनिश्चित हो सके कि आप समझते हैं कि आपके द्वारा प्रदान की जाने वाली किसी भी व्यक्तिगत जानकारी का उपयोग कैसे किया जाएगा।</p>\r\n\r\n<p>नोट: इस गोपनीयता नीति में निर्धारित गोपनीयता प्रथाएं केवल राहत के लिए हैं। यदि आप अन्य वेब साइटों से लिंक करते हैं, तो कृपया उन साइटों पर पोस्ट की गई गोपनीयता नीतियों की समीक्षा करें।</p>\r\n\r\n<p>सूचना का संग्रह</p>\r\n\r\n<p>हम अपने आगंतुकों द्वारा स्वेच्छा से सबमिट किए जाने पर व्यक्तिगत रूप से पहचान योग्य जानकारी, जैसे नाम, डाक पते, ईमेल पते आदि एकत्र करते हैं। आपके द्वारा प्रदान की जाने वाली जानकारी का उपयोग आपके विशिष्ट अनुरोध को पूरा करने के लिए किया जाता है। इस जानकारी का उपयोग केवल आपके विशिष्ट अनुरोध को पूरा करने के लिए किया जाता है, जब तक कि आप हमें इसे किसी अन्य तरीके से उपयोग करने की अनुमति नहीं देते, उदाहरण के लिए आपको हमारी किसी मेलिंग सूची में जोड़ने के लिए।</p>\r\n\r\n<p>&nbsp;कुकी/ट्रैकिंग तकनीक</p>\r\n\r\n<p>साइट दी गई सुविधाओं के आधार पर कुकीज़ और ट्रैकिंग तकनीक का उपयोग करती है। कुकीज़ और ट्रैकिंग तकनीक ब्राउज़र प्रकार और ऑपरेटिंग सिस्टम जैसी जानकारी एकत्र करने, साइट पर आने वालों की संख्या पर नज़र रखने और यह समझने के लिए उपयोगी हैं कि विज़िटर साइट का उपयोग कैसे करते हैं। कूकीज साईट को दर्शकों हेतु कस्टमाइज करने में भी सहायता कर सकती हैं। कुकीज़ और अन्य ट्रैकिंग तकनीक के माध्यम से व्यक्तिगत जानकारी एकत्र नहीं की जा सकती है, हालांकि, यदि आपने पहले व्यक्तिगत रूप से पहचान योग्य जानकारी प्रदान की है, तो कुकीज़ ऐसी जानकारी से जुड़ी हो सकती हैं। कुल कुकी और ट्रैकिंग जानकारी को तृतीय पक्षों के साथ साझा किया जा सकता है।</p>\r\n\r\n<p>सूचना का वितरण</p>\r\n\r\n<p>हम नीचे सूचीबद्ध कुछ व्यक्तिगत रूप से पहचान योग्य जानकारी को तृतीय पक्ष सेवाओं के सामने प्रकट कर सकते हैं:</p>\r\n\r\n<p>जानकारी जो आप हमें प्रदान करते हैं जैसे नाम, ईमेल, मोबाइल फोन नंबर</p>\r\n\r\n<p>जब आप हमारी सेवा का उपयोग और उपयोग करते हैं तो हम जो जानकारी एकत्र करते हैं, उसमें डिवाइस की जानकारी, स्थान और नेटवर्क वाहक शामिल हैं</p>\r\n\r\n<p>यह जानकारी तृतीय पक्ष सेवा प्रदाताओं के साथ साझा की जाती है ताकि हम:</p>\r\n\r\n<p>आपके लिए ऐप को निजीकृत करें</p>\r\n\r\n<p>व्यवहार विश्लेषण करें</p>\r\n\r\n<p>डेटा सुरक्षा के प्रति प्रतिबद्धता</p>\r\n\r\n<p>आपकी व्यक्तिगत पहचान योग्य जानकारी सुरक्षित रखी जाती है।; केवल अधिकृत कर्मचारियों, एजेंटों और ठेकेदारों (जो जानकारी को सुरक्षित और गोपनीय रखने के लिए सहमत हुए हैं) के पास ही इस जानकारी तक पहुंच है।</p>\r\n\r\n<p>ऑनलाइन विज्ञापन जिसका हम उपयोग करते हैं</p>\r\n\r\n<p>हम इंटरनेट पर विज्ञापन देने के लिए रीमार्केटिंग के लिए Google Analytics विज्ञापन सुविधाओं का उपयोग करते हैं। रीमार्केटिंग आपकी मशीन पर कुकी रखकर राहत ऐप के किन हिस्सों को देखा गया है, इसके आधार पर आपके अनुरूप प्रासंगिक विज्ञापन प्रदर्शित करेगा। यह कुकी किसी भी तरह से आपकी पहचान नहीं करती है या आपके कंप्यूटर तक पहुंच प्रदान नहीं करती है। कुकी का उपयोग यह कहने के लिए किया जाता है कि \"यह व्यक्ति इस पृष्ठ पर गया था, इसलिए उन्हें उस पृष्ठ से संबंधित विज्ञापन दिखाएं।\" Google Analytics रीमार्केटिंग की सहायता से हम अपनी मार्केटिंग को आपकी आवश्यकताओं के अनुसार बेहतर ढंग से अनुकूलित कर सकते हैं और केवल वही विज्ञापन प्रदर्शित कर सकते हैं जो आपके लिए प्रासंगिक हैं।</p>\r\n\r\n<p>यदि आप हमारी रीमार्केटिंग में भाग नहीं लेना चाहते हैं, तो आप इसका उपयोग करके ऑप्ट आउट कर सकते हैं</p>\r\n\r\n<p>हम इस नीति में बदलाव करने का अधिकार सुरक्षित रखते हैं।; इस नीति में किसी भी परिवर्तन को पोस्ट किया जाएगा।</p>','2020-06-30 03:33:15','Y'),(30,'Privacy Policy','privacy-policy','<style>\r\np {font-size:40px !important; padding:20px; text-align:justify;}\r\n</style>\r\n\r\n<p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">गौरी ब्रांड आपकी गोपनीयता की सराहना और सम्मान करता है।. इस साइट या किसी अन्य प्रपत्र के माध्यम से आपके द्वारा प्रस्तुत की गई कोई भी / सभी जानकारी अत्यंत गोपनीयता के अधीन है।.</font></p>\r\n\r\n<p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">सूचना का संग्रह।</font></p>\r\n\r\n<p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">गौरी&nbsp; कैटल फीडकपिला कैटल फीड अपनी साइट के आगंतुकों की वेबसाइट के माध्यम से जानकारी एकत्र करता है जो पूछताछ करने में रुचि रखते हैं, वेबसाइट पर उपलब्ध इलेक्ट्रॉनिक रूपों के माध्यम से अपडेट या सामान्य प्रतिक्रिया के लिए सदस्यता लेते हैं।.</font></p>\r\n\r\n<p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">हमसे संपर्क करें।</font></p>\r\n\r\n<p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">गौरी ब्रांड&nbsp; फीड की वेबसाइट में ऐसी विशेषताएं हैं जहां साइट आगंतुक और ग्राहक इलेक्ट्रॉनिक रूप से कपिला कैटल फीड को जानकारी प्रस्तुत कर सकते हैं।. इस तरह के सबमिशन में विशिष्ट अनुरोधों का सबसे अच्छा जवाब देने के लिए आवश्यक प्रश्न, प्रतिक्रिया या अन्य जानकारी शामिल होती है।. इसके अलावा, गौरी ब्रांड फीड आंतरिक प्रशासनिक उद्देश्यों के लिए वेबसाइट के माध्यम से भेजे गए ई-मेल और अन्य जानकारी को बनाए रख सकती है और आपके अनुरोधों के साथ बेहतर सेवा करने में मदद कर सकती है।.</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">स्वचालित डेटा संग्रह।</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">गौरी ब्रांड फीड अपनी वेबसाइट पर सभी आगंतुकों के दिनांक, समय, ब्राउज़र प्रकार, नेविगेशन इतिहास और आईपी पते सहित अन्य प्रकार के आगंतुक विवरण एकत्र करता है।. एकत्र की गई जानकारी का उपयोग आंतरिक सुरक्षा ऑडिट, सिस्टम प्रशासन उद्देश्यों के लिए प्रवृत्ति विश्लेषण और वेबसाइट पर वेबसाइट के उपयोगकर्ता व्यवहार और उपयोग पैटर्न को इकट्ठा करने के लिए भी किया जाता है।. गौरी ब्रांड फीड इस जानकारी का उपयोग वेबसाइट के आगंतुकों के बारे में अधिक जानने और जानने के लिए कर सकती है, वेबसाइट के माध्यम से प्रदान की गई सामग्री / जानकारी के प्रकार के बारे में उनकी प्राथमिकताएं।. गौरी ब्रांड&nbsp; फीड इस जानकारी का उपयोग उन सामग्रियों की सेवा के लिए करेगी जो उपयोगकर्ताओं के लिए अधिक उपयुक्त हैं या अपने प्रतिनिधियों से ऑफ़र के बारे में आगंतुकों से संपर्क करने के लिए, जो उनके लिए रुचि का हो सकता है।. गौरी ब्रांड फीड इस जानकारी को किसी तीसरे पक्ष को नहीं बताती है।.</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">जानकारी साझा करना।</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">गौरी ब्रांड&nbsp; फीड अपने ग्राहक और वेबसाइट आगंतुक जानकारी को तीसरे पक्ष को नहीं बेचती, किराए पर देती या पट्टे पर नहीं देती।. गौरी ब्रांड फीड समूह की कंपनियों / डिवीजनों के अलावा तीसरे पक्ष के साथ व्यक्तिगत रूप से पहचान योग्य जानकारी साझा नहीं करता है।. जानकारी को तीसरे पक्ष के साथ साझा किया जा सकता है जो अपने उत्पाद (ओं) / सेवा (ओं) को प्रदान करने में कपिला कैटल फीड के एजेंटों के रूप में कार्य कर रहे हैं, और जो केवल उस उद्देश्य के लिए इसका उपयोग करने के लिए सहमत हैं और जानकारी को सुरक्षित और गोपनीय रखते हैं।. कपिला कैटल फीड भी जानकारी का खुलासा करेगी कि यह कानून द्वारा ऐसा करने के लिए आवश्यक होने पर बनाए रखता है या।, विशेष मामलों में।, जब कपिला कैटल फीड के पास यह विश्वास करने का कारण है कि इस जानकारी का खुलासा करना आवश्यक है।, किसी ऐसे व्यक्ति के खिलाफ संपर्क करें या कानूनी कार्रवाई करें, जिसके साथ चोट लग सकती है या हस्तक्षेप हो सकता है। (या तो जानबूझकर या अनजाने में।) इसके अधिकार या संपत्ति।. कपिला कैटल फीड कुल जानकारी साझा कर सकती है, जो व्यक्तिगत रूप से पहचान योग्य नहीं है, दूसरों के साथ।.</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">व्यक्तिगत जानकारी को सही करना और अपडेट करना।</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">यदि आपके द्वारा साइट के माध्यम से प्रस्तुत की गई जानकारी में कोई बदलाव है और आप उसी को सही या अपडेट करना चाह सकते हैं, तो आप वेबसाइट के माध्यम से हमारे प्रतिनिधियों से संपर्क कर सकते हैं और अद्यतन किए जाने वाले विवरण प्रदान कर सकते हैं।.</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">सुरक्षा।</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">गौरी ब्रांड फीड वेबसाइट के माध्यम से इसके द्वारा प्राप्त जानकारी की सुरक्षा के लिए उचित सावधानियों का उपयोग करता है।. ऐसी जानकारी वेब सर्वर पर संग्रहीत की जाती है, जो सुरक्षित वातावरण में संग्रहीत होती हैं।. गौरी ब्रांड फीड किसी भी तीसरे पक्ष द्वारा अपने सर्वर पर कपिला कैटल फीड द्वारा संग्रहीत जानकारी के लिए किसी भी अनधिकृत पहुंच के लिए जिम्मेदार नहीं होगा।. केवल गौरी ब्रांड फीड के कर्मचारी, जिन्हें किसी विशिष्ट कार्य को करने के लिए जानकारी की आवश्यकता होती है, उन्हें ऐसी जानकारी तक पहुंच प्रदान की जाती है।.</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">लिंक।</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">गौरी ब्रांड फीड वेबसाइट में अन्य गैर कपिला कैटल फीड वेबसाइटों के लिंक हो सकते हैं।. गौरी ब्रांड फीड ऐसी अन्य साइटों की गोपनीयता प्रथाओं या सामग्री के लिए जिम्मेदार नहीं है।. गौरी ब्रांड अपनी साइट के उपयोगकर्ताओं को सलाह देती है कि जब वे गौरी ब्रांड की वेबसाइट छोड़ते हैं, तो वे जागरूक हों, और उन्हें प्रत्येक वेबसाइट के गोपनीयता कथन को पढ़ने के लिए प्रोत्साहित करें, जिसमें गौरी ब्रांड फीड लिंक प्रदान कर सकती है।.</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">अधिसूचना और परिवर्तन।</font></p><p style=\"margin-bottom: 18px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-stretch: inherit; line-height: inherit; vertical-align: baseline;\"><font color=\"#444444\" face=\"Open Sans Regular, Geneva, Arial, sans-serif\">गौरी ब्रांड फीड ने इस पृष्ठ में अपनी गोपनीयता नीति में किसी भी परिवर्तन या संशोधन को अद्यतन करने की घोषणा की।. वेबसाइट आगंतुकों से अनुरोध है कि वे गोपनीयता नीति में किए गए परिवर्तनों के बारे में सूचित करने के लिए नियमित रूप से इस अनुभाग की जाँच करें।. यदि आपको हमारी गोपनीयता नीति के बारे में अधिक जानकारी की आवश्यकता है, तो इस साइट पर दिए गए रूपों में से एक के माध्यम से कपिला कैटल फ़ीड से संपर्क करें।.</font></p>','2020-09-01 04:17:40','Y'),(31,'Contact Us','contact-us','<style>\r\np, ul {\r\ntext-align:justify;\r\nfont-size:40px;\r\nmargin-bottom:30px;\r\npadding:20px;\r\n}\r\n</style>\r\n\r\n<p>वापसी और धनवापसी नीति:</p>\r\n\r\n<p>आप बिना कोई कारण बताए 30 दिनों के भीतर अपने आदेश को रद्द करने के हकदार हैं।</p>\r\n\r\n<p>किसी ऑर्डर को रद्द करने की समय सीमा उस तारीख से 30 दिन है जब आपने सामान प्राप्त किया था या जिस पर आपके द्वारा नियुक्त किया गया कोई तीसरा पक्ष, जो वाहक नहीं है, वितरित उत्पाद का कब्जा लेता है।</p>\r\n\r\n<p>रद्द करने के अपने अधिकार का प्रयोग करने के लिए, आपको स्पष्ट विवरण के माध्यम से हमें अपने निर्णय के बारे में सूचित करना होगा।</p>\r\n\r\n<p>आप हमें अपने निर्णय के बारे में ई-मेल skscotexpl@gmail.com पर सूचित कर सकते हैं|</p>\r\n\r\n<p>हम आपको लौटाए गए माल को प्राप्त करने के दिन से 30 दिनों के भीतर प्रतिपूर्ति नहीं करेंगे। हम भुगतान के उसी तरीके का उपयोग करेंगे जैसा आपने ऑर्डर के लिए किया था, और इस तरह की प्रतिपूर्ति के लिए आपको कोई शुल्क नहीं देना होगा।</p>\r\n\r\n<p>रिटर्न के लिए शर्तें:</p>\r\n\r\n<p>सामान वापसी के योग्य होने के लिए, कृपया सुनिश्चित करें कि:</p>\r\n\r\n<ul>\r\n<li>माल पिछले 30 दिनों में खरीदा गया था </li>\r\n<li>माल मूल पैकेजिंग में हैं </li>\r\n</ul>\r\n\r\n<p>निम्नलिखित माल वापस नहीं किया जा सकता है:</p>\r\n\r\n<ul>\r\n<li>आपके विनिर्देशों या स्पष्ट रूप से वैयक्तिकृत किए गए सामानों की आपूर्ति।</li>\r\n<li>माल की आपूर्ति जो उनकी प्रकृति के अनुसार वापस करने के लिए उपयुक्त नहीं है, उदाहरण के लिए माल जो तेजी से बिगड़ता है या जहां समाप्ति की तारीख समाप्त हो जाती है।</li>\r\n<li>माल की आपूर्ति जो स्वास्थ्य सुरक्षा या स्वच्छता कारणों से वापसी के लिए उपयुक्त नहीं है और डिलीवरी के बाद बंद कर दी गई थी।</li>\r\n<li>माल की आपूर्ति, जो डिलीवरी के बाद, उनकी प्रकृति के अनुसार, अन्य वस्तुओं के साथ अविभाज्य रूप से मिश्रित होती है।</li>\r\n<li>हम किसी भी माल की वापसी को अस्वीकार करने का अधिकार सुरक्षित रखते हैं जो हमारे विवेकाधिकार पर उपरोक्त वापसी शर्तों को पूरा नहीं करता है।</li>\r\n</ul>\r\n\r\n<p>सामान लौटाना</p>\r\n\r\n<p>आप हमें माल वापस करने की लागत और जोखिम के लिए जिम्मेदार हैं। आपको माल निम्नलिखित पते पर भेजना चाहिए:</p>\r\n\r\n<p>ई-20 रिको इंडस्ट्रियल एरिया रिंगस</p>\r\n\r\n<p>हमें माल के क्षतिग्रस्त होने या वापसी शिपमेंट में खो जाने के लिए जिम्मेदार नहीं ठहराया जा सकता है। इसलिए, हम एक बीमाकृत और ट्रैक करने योग्य मेल सेवा की अनुशंसा करते हैं। हम माल की वास्तविक प्राप्ति या प्राप्त वापसी वितरण के प्रमाण के बिना धनवापसी जारी करने में असमर्थ हैं।</p>\r\n\r\n<p>संपर्क करें</p>\r\n<p>यदि आपके पास हमारी वापसी और धनवापसी नीति के बारे में कोई प्रश्न हैं, तो कृपया हमें ई-मेल skscotexpl@gmail.com पर संपर्क करें।</p>','2020-09-03 13:25:43','Y'),(32,'Refund','refund','<pre class=\"tw-data-text tw-text-large tw-ta\" data-placeholder=\"Translation\" id=\"tw-target-text\" dir=\"ltr\" style=\"unicode-bidi: isolate; font-size: 24px; line-height: 32px; background-color: rgb(48, 49, 52); border-width: initial; border-style: none; border-color: initial; padding: 2px 0.14em 2px 0px; position: relative; margin-top: -2px; margin-bottom: -2px; resize: none; font-family: inherit; overflow: hidden; width: 270px; white-space: pre-wrap; color: rgb(232, 234, 237);\"><span class=\"Y2IQFc\" lang=\"hi\">वापसी और धनवापसी नीति:\r\nआप बिना कोई कारण बताए 24 घंटों के भीतर अपने आदेश को रद्द करने के हकदार हैं।\r\n\r\nकिसी ऑर्डर को रद्द करने की समय सीमा उस समय से 24 घंटे है जब आपने सामान प्राप्त किया था या जिस पर आपके द्वारा नियुक्त किया गया कोई तीसरा पक्ष, जो वाहक नहीं है, वितरित उत्पाद का कब्जा लेता है।\r\n\r\nरद्द करने के अपने अधिकार का प्रयोग करने के लिए, आपको स्पष्ट विवरण के माध्यम से हमें अपने निर्णय के बारे में सूचित करना होगा।\r\n\r\nआप हमें अपने निर्णय के बारे में ई-मेल skscotexpl@gmail.com पर सूचित कर सकते हैं\r\n\r\nहम आपको लौटाए गए माल को प्राप्त करने के दिन से 24  घंटों के भीतर प्रतिपूर्ति नहीं करेंगे। हम भुगतान के उसी तरीके का उपयोग करेंगे जैसा आपने ऑर्डर के लिए किया था, और इस तरह की प्रतिपूर्ति के लिए आपको कोई शुल्क नहीं देना होगा।\r\n\r\nरिटर्न के लिए शर्तें:\r\nसामान वापसी के योग्य होने के लिए, कृपया सुनिश्चित करें कि:\r\n\r\nमाल पिछले 24 घंटों में खरीदा गया था\r\nमाल मूल पैकेजिंग में हैं\r\nनिम्नलिखित माल वापस नहीं किया जा सकता है:\r\n\r\nआपके विनिर्देशों या स्पष्ट रूप से वैयक्तिकृत किए गए सामानों की आपूर्ति।\r\nमाल की आपूर्ति जो उनकी प्रकृति के अनुसार वापस करने के लिए उपयुक्त नहीं है, उदाहरण के लिए माल जो तेजी से बिगड़ता है या जहां समाप्ति की तारीख समाप्त हो जाती है।\r\nमाल की आपूर्ति जो स्वास्थ्य सुरक्षा या स्वच्छता कारणों से वापसी के लिए उपयुक्त नहीं है और डिलीवरी के बाद बंद कर दी गई थी।\r\nमाल की आपूर्ति, जो डिलीवरी के बाद, उनकी प्रकृति के अनुसार, अन्य वस्तुओं के साथ अविभाज्य रूप से मिश्रित होती है।\r\nहम किसी भी माल की वापसी को अस्वीकार करने का अधिकार सुरक्षित रखते हैं जो हमारे विवेकाधिकार पर उपरोक्त वापसी शर्तों को पूरा नहीं करता है।\r\n\r\nसामान लौटाना\r\nआप हमें माल वापस करने की लागत और जोखिम के लिए जिम्मेदार हैं। आपको माल निम्नलिखित पते पर भेजना चाहिए:\r\n\r\nई-20 रिको इंडस्ट्रियल एरिया रिंगस\r\n\r\nहमें माल के क्षतिग्रस्त होने या वापसी शिपमेंट में खो जाने के लिए जिम्मेदार नहीं ठहराया जा सकता है। इसलिए, हम एक बीमाकृत और ट्रैक करने योग्य मेल सेवा की अनुशंसा करते हैं। हम माल की वास्तविक प्राप्ति या प्राप्त वापसी वितरण के प्रमाण के बिना धनवापसी जारी करने में असमर्थ हैं।\r\n\r\n\r\nसंपर्क करें\r\nयदि आपके पास हमारी वापसी और धनवापसी नीति के बारे में कोई प्रश्न हैं, तो कृपया हमें ई-मेल skscotexpl@gmail.com पर संपर्क करें।</span></pre>','2020-09-01 04:17:40','N');
