  `password` varchar(191) DEFAULT NULL,
  `otp` int DEFAULT NULL,
  `referral_code` varchar(100) DEFAULT NULL,
  `role_id` int NOT NULL,
  `status` tinyint(1) NOT NULL DEFAULT '1',
  `token` text,
  `created` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `modified` timestamp NULL DEFAULT NULL,
  `state_id` varchar(250) DEFAULT NULL,
  `gst_no` varchar(250) DEFAULT NULL,
  `account_name` varchar(500) DEFAULT NULL,
  `bank_name` varchar(100) DEFAULT NULL,
  `account_number` varchar(200) DEFAULT NULL,
  `ifsc` varchar(15) DEFAULT NULL,
  `branch` varchar(100) DEFAULT NULL,
  `user_address_id` varchar(250) DEFAULT NULL,
  `address` varchar(250) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `address_1` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `pincode_1` int DEFAULT NULL,
  `address_2` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `pincode_2` int DEFAULT NULL,
  `address_3` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `pincode_3` int DEFAULT NULL,
  `notification_counter` bigint DEFAULT NULL,
  `instagram` varchar(250) DEFAULT NULL,
  `fackbook` varchar(250) DEFAULT NULL,
  `twitter` varchar(250) DEFAULT NULL,
  `youtube` varchar(250) DEFAULT NULL,
  `villagename` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `animalCount` int NOT NULL,
  `milkQuantity` varchar(200) NOT NULL,
  `helpline_number` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `contact_email` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `factroy_address` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `sms_mobile` bigint DEFAULT NULL,
